from itertools import combinations

class Solution:
    def maxScore(self, nums1, nums2, k):
        # Genuinely independent from the DP: directly enumerate every strictly
        # increasing index subsequence of length k from nums1 and every one from
        # nums2 (itertools.combinations already yields them in sorted/increasing
        # order), pair the t-th chosen index of each sequence together, and take
        # the best total. Only intended for small n, m (this file only feeds it
        # small edge_inputs; large sizes are exercised via the DP-only stress path).
        n, m = len(nums1), len(nums2)
        best = None
        for idx1 in combinations(range(n), k):
            for idx2 in combinations(range(m), k):
                score = 0
                for t in range(k):
                    score += nums1[idx1[t]] * nums2[idx2[t]]
                if best is None or score > best:
                    best = score
        return best

