var maxScore = function(nums1, nums2, k) {
    const n = nums1.length, m = nums2.length;
    const NEG = -1e15;
    let prev = [];
    for (let i = 0; i <= n; i++) prev.push(new Array(m + 1).fill(0));
    for (let t = 1; t <= k; t++) {
        const cur = [];
        for (let i = 0; i <= n; i++) cur.push(new Array(m + 1).fill(NEG));
        for (let i = 1; i <= n; i++) {
            const row = cur[i];
            const above = cur[i - 1];
            const diagRow = prev[i - 1];
            const a = nums1[i - 1];
            for (let j = 1; j <= m; j++) {
                let best = row[j - 1];
                if (above[j] > best) best = above[j];
                const diag = diagRow[j - 1];
                const candidate = diag + a * nums2[j - 1];
                if (candidate > best) best = candidate;
                row[j] = best;
            }
        }
        prev = cur;
    }
    return prev[n][m];
};
